import 'package:flutter/material.dart';
import '../../core/app_theme.dart';
import '../../services/session_service.dart';
import '../login_page.dart';

class AdminProfilePage extends StatelessWidget { const AdminProfilePage({super.key, required this.user}); final Map<String, dynamic> user; @override Widget build(BuildContext context) => SingleChildScrollView(child: Column(children: [const SizedBox(height: 35), const Text('Profil', style: TextStyle(fontSize: 19)), const SizedBox(height: 40), const CircleAvatar(radius: 62, backgroundColor: alpenSoftBlue, child: Icon(Icons.person, color: alpenBlue, size: 66)), const SizedBox(height: 18), Text((user['name'] ?? 'ADMIN').toString().toUpperCase(), style: const TextStyle(fontWeight: FontWeight.w700, color: Color(0xFF5A5A5A))), const SizedBox(height: 48), _Setting(icon: Icons.edit_outlined, label: 'Edit Data Diri'), _Setting(icon: Icons.settings_outlined, label: 'Pengaturan Akun'), _Setting(icon: Icons.info_outline, label: 'Tentang Aplikasi Ini'), _Setting(icon: Icons.logout, label: 'Keluar', onTap: () => _logout(context))])); }
class _Setting extends StatelessWidget { const _Setting({required this.icon, required this.label, this.onTap}); final IconData icon; final String label; final VoidCallback? onTap; @override Widget build(BuildContext context) => InkWell(onTap: onTap, child: Container(width: double.infinity, padding: const EdgeInsets.symmetric(horizontal: 42, vertical: 17), margin: const EdgeInsets.only(bottom: 12), color: const Color(0xFFF9F9F9), child: Row(children: [Icon(icon, color: Colors.grey[700]), const SizedBox(width: 18), Text(label, style: const TextStyle(color: Color(0xFF5A5A5A)))]))); }
Future<void> _logout(BuildContext context) => showDialog<void>(context: context, builder: (_) => AlertDialog(shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(20)), icon: const CircleAvatar(radius: 34, backgroundColor: Color(0xFFFFDDDD), child: Icon(Icons.question_mark, color: Colors.red, size: 38)), title: const Text('Apakah Anda yakin Ingin Keluar dari akun admin?', textAlign: TextAlign.center, style: TextStyle(fontSize: 17, fontWeight: FontWeight.w800)), actions: [TextButton(onPressed: () => Navigator.pop(context), child: const Center(child: Text('Cancel', style: TextStyle(color: Colors.red, fontWeight: FontWeight.w700)))), SizedBox(width: double.infinity, child: ElevatedButton(onPressed: () async { await SessionService.clear(); if (context.mounted) Navigator.pushAndRemoveUntil(context, MaterialPageRoute(builder: (_) => const LoginPage()), (_) => false); }, child: const Text('Log Out')))]));
